<?php require_once __DIR__ . '/../includes/auth.php'; require_admin(); if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$status=in_array($_POST['status'],['new','reviewing','approved','declined'],true)?$_POST['status']:'new';db()->prepare('UPDATE submissions SET status=? WHERE id=?')->execute([$status,(int)$_POST['id']]);header('Location: '.url('admin/submissions.php'));exit;} $submissions=db()->query('SELECT * FROM submissions ORDER BY created_at DESC')->fetchAll();require __DIR__.'/partials/header.php';?><div class="admin-heading"><div><p class="eyebrow">Community</p><h1>Feature submissions</h1></div></div><section class="admin-panel submission-list"><?php foreach($submissions as $item):?><article><div><h2><?=e($item['business_name'])?></h2><p><strong><?=e($item['owner_name'])?></strong> · <a href="mailto:<?=e($item['email'])?>"><?=e($item['email'])?></a></p><p><?=nl2br(e($item['message']))?></p><?php if($item['website']):?><a href="<?=e($item['website'])?>" rel="noopener" target="_blank">Website ↗</a><?php endif;?></div><form method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="id" value="<?=e((string)$item['id'])?>"><label>Status<select name="status"><?php foreach(['new','reviewing','approved','declined'] as $status):?><option value="<?=$status?>" <?=$status===$item['status']?'selected':''?>><?=ucfirst($status)?></option><?php endforeach;?></select></label><button>Update</button></form></article><?php endforeach;?></section><?php require __DIR__.'/partials/footer.php'; ?>
